using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 renamed the discriminator JSON property from "Discriminator" to "$type".
            // Keep the old name so existing 500K documents and direct SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // EF9 no longer prepends the discriminator to the JSON "id" value.
            // Existing docs use "Product|123" format — this preserves that convention.
            b.HasDiscriminatorInJsonId();

            // EF9 maps the CLR key directly to the JSON "id" property and stops
            // persisting the key under a separate JSON property. Restore the EF8
            // shadow-property behavior so existing documents keep their "Id" field.
            b.HasShadowId();
        });

        // HasIndex removed — EF9 Cosmos provider now throws (Cosmos indexes all
        // properties by default; manage custom indexing via the Azure Portal).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

